#include<bits/stdc++.h>
using namespace std;
string s[101];
int main()
{
	int n,k;
	cin>>n>>k;
	for(int i=0;i<n;i++){
		cin>>s[i];
	}
	bool flag=true;
	int hang=k;
	int word=0;
	for(int i=0;flag==true;i++){		
		
		if(s[word].length()<hang){
			hang-=s[word].length();
			cout<<s[word];
			word++;
			cout<<" ";				
		}
		else if(s[word].length()==hang){
			cout<<s[word];
			word++;
			cout<<endl;
			hang=k;
		}
		else if(s[word].length()>hang){
			cout<<endl;
			hang=k;
		}
		if(word==n){
			break;
		}
	}
}
